          "locked": true,
          "lessonText": "# Advanced BIT Operations\n\nBeyond basic sum queries.\n\n## K-th Element\n\nFind k-th smallest element (1-indexed):\n\n```cpp\nint findKth(int k) {\n    int idx = 0;\n    int bitmask = highestPowerOf2(n);\n    \n    while (bitmask != 0) {\n        int nextIdx = idx + bitmask;\n        if (nextIdx <= n && tree[nextIdx] < k) {\n            idx = nextIdx;\n            k -= tree[nextIdx];\n        }\n        bitmask >>= 1;\n    }\n    \n    return idx + 1;\n}\n```\n\n## Min/Max Queries\n\n### Min BIT\n```cpp\nstruct MinBIT {\n    vector<int> tree;\n    int n;\n    \n    MinBIT(int size) : n(size) {\n        tree.assign(n + 1, INT_MAX);\n    }\n    \n    void update(int idx, int val) {\n        while (idx <= n) {\n            tree[idx] = min(tree[idx], val);\n            idx += idx & (-idx);\n        }\n    }\n    \n    int query(int idx) {\n        int result = INT_MAX;\n        while (idx > 0) {\n            result = min(result, tree[idx]);\n            idx -= idx & (-idx);\n        }\n        return result;\n    }\n};\n```\n\n### Max BIT\n```cpp\nstruct MaxBIT {\n    vector<int> tree;\n    int n;\n    \n    MaxBIT(int size) : n(size) {\n        tree.assign(n + 1, INT_MIN);\n    }\n    \n    void update(int idx, int val) {\n        while (idx <= n) {\n            tree[idx] = max(tree[idx], val);\n            idx += idx & (-idx);\n        }\n    }\n    \n    int query(int idx) {\n        int result = INT_MIN;\n        while (idx > 0) {\n            result = max(result, tree[idx]);\n            idx -= idx & (-idx);\n        }\n        return result;\n    }\n};\n```\n\n## XOR BIT\n\n```cpp\nstruct XorBIT {\n    vector<int> tree;\n    int n;\n    \n    void update(int idx, int val) {\n        while (idx <= n) {\n            tree[idx] ^= val;\n            idx += idx & (-idx);\n        }\n    }\n    \n    int query(int idx) {\n        int result = 0;\n        while (idx > 0) {\n            result ^= tree[idx];\n            idx -= idx & (-idx);\n        }\n        return result;\n    }\n};\n```\n\n## Coordinate Compression\n\n```cpp\nvoid compressCoordinates(vector<int>& arr) {\n    auto sorted = arr;\n    sort(sorted.begin(), sorted.end());\n    sorted.erase(unique(sorted.begin(), sorted.end()), \n                  sorted.end());\n    \n    for (int& val : arr) {\n        val = lower_bound(sorted.begin(), sorted.end(), val) \n              - sorted.begin() + 1;\n    }\n}\n```\n\n## Advanced Operations\n\n| Operation | Description |\n|-----------|-------------|\n| K-th element | Order statistic |\n| Count range | Elements in range |\n| Min/Max | Prefix min/max |\n| XOR | Prefix XOR |\n| GCD | Prefix GCD |\n| Compression | Large values |\n\n## Use Cases\n\n- **Order statistics**: K-th element\n- **Counting**: Range count queries\n- **Min/Max**: Prefix min/max\n- **XOR**: Prefix XOR operations\n- **Large values**: Coordinate compression\n"
